window.BLUEFORCE_QUESTION_BANKS=window.BLUEFORCE_QUESTION_BANKS||{};window.BLUEFORCE_QUESTION_BANKS["platform-administrator"]={"categoryOrder":["All","Configuration and Setup","Object Manager and Lightning App Builder","Sales and Marketing Applications","Service and Support Applications","Productivity and Collaboration","Data and Analytics Management","Automation","Agentforce"],"questions":[{"id":1,"category":"Configuration and Setup","select":1,"question":"Two sales users have the same profile, but only one of them should be allowed to export reports. What should the administrator use?","options":["Change the organization-wide defaults","Create a sharing rule","Create a second role","Assign a permission set to the individual user"],"answers":[3],"explanation":"A permission set grants additional permissions to selected users without changing the baseline access provided by their profile. Roles and sharing settings control record visibility, not system permissions such as exporting reports.","tip":"Profiles provide the baseline. Permission sets add exceptions. Sharing tools answer a different question: which records can the user see?"},{"id":2,"category":"Configuration and Setup","select":1,"question":"Opportunity organization-wide defaults are Private. Sales managers must automatically see opportunities owned by users below them. Which feature provides this access?","options":["Role hierarchy","Login IP ranges","Field-level security","Permission set group"],"answers":[0],"explanation":"The role hierarchy can open record access upward so managers can see records owned by users below them when organization-wide defaults are restrictive. Permission sets and field-level security control permissions, not hierarchical record visibility.","tip":"Think of record access as layers: organization-wide defaults establish the floor, then role hierarchy, sharing rules, teams, and manual sharing can open access."},{"id":3,"category":"Configuration and Setup","select":1,"question":"All high-value accounts in the Healthcare industry must be shared read-only with a cross-functional public group. What is the most maintainable solution?","options":["A validation rule","A criteria-based sharing rule","A new profile","A compact layout"],"answers":[1],"explanation":"A criteria-based sharing rule automatically shares records that meet field-based conditions with roles, roles and subordinates, or public groups. It is designed for repeatable record access beyond the organization-wide defaults.","tip":"When access depends on record values rather than ownership, look for a criteria-based sharing rule."},{"id":4,"category":"Configuration and Setup","select":1,"question":"Users with a specific profile must be completely blocked from logging in outside the corporate network. Which setting should the administrator configure?","options":["A sharing rule","Network Access trusted IP ranges","Profile login IP ranges","Session timeout"],"answers":[2],"explanation":"Login IP ranges on a profile restrict where users assigned to that profile can log in. Network Access trusted IP ranges reduce identity verification challenges but do not by themselves block login from other locations.","tip":"Trusted IP ranges reduce verification. Profile login IP ranges enforce a hard login restriction."},{"id":5,"category":"Configuration and Setup","select":2,"question":"An employee leaves unexpectedly. Which two actions best protect the org while preserving ownership and history?","options":["Delete the user record","Freeze the user immediately","Change every record to Public Read/Write","Transfer important records and then deactivate the user"],"answers":[1,3],"explanation":"Freezing blocks login immediately while the administrator resolves dependencies. Salesforce users are normally deactivated rather than deleted, and their records can be transferred before deactivation so history remains intact.","tip":"Freeze is immediate containment. Deactivate is the durable state. Users are preserved for audit history rather than deleted."},{"id":6,"category":"Configuration and Setup","select":1,"question":"A user in France needs French date formats and number separators, while the rest of the org uses United States formatting. What should be changed?","options":["The user's locale","The user's role","The organization's fiscal year","The account currency"],"answers":[0],"explanation":"A user's locale controls the display format for dates, times, names, addresses, numbers, and currencies. It does not alter record access or the organization's fiscal structure.","tip":"Locale is presentation. Language controls translated labels. Time zone controls displayed time. Currency settings control monetary values."},{"id":7,"category":"Configuration and Setup","select":1,"question":"A company's fiscal year begins on February 1 and follows normal calendar months. Which configuration is appropriate?","options":["A user-level locale change","A standard fiscal year with February as the start month","A custom object for fiscal periods","A custom fiscal year using 4-4-5 periods"],"answers":[1],"explanation":"A standard fiscal year can begin in any month while retaining normal calendar months. Custom fiscal years are intended for nonstandard structures such as 4-4-5 accounting periods.","tip":"A different starting month does not automatically require a custom fiscal year."},{"id":8,"category":"Configuration and Setup","select":1,"question":"A regional operations lead should reset passwords and manage users only in one department without receiving full System Administrator access. What should be configured?","options":["A dashboard running user","A territory model","Delegated administration","A queue"],"answers":[2],"explanation":"Delegated administration allows selected non-admin users to perform limited administrative tasks for specified users, roles, and custom objects. It follows least-privilege principles without granting unrestricted Setup access.","tip":"When someone needs a narrow slice of administrative responsibility, consider delegated administration before a powerful profile."},{"id":9,"category":"Object Manager and Lightning App Builder","select":1,"question":"An account must display the sum of Amount from all related custom Invoice records. Which relationship supports a native roll-up summary field?","options":["Indirect lookup relationship","Lookup relationship","External lookup relationship","Master-detail relationship"],"answers":[3],"explanation":"Native roll-up summary fields operate across a master-detail relationship and are created on the master record. They can count, sum, and calculate minimum or maximum values from related detail records.","tip":"Native roll-up summary usually signals master-detail. A plain lookup does not provide native roll-ups."},{"id":10,"category":"Object Manager and Lightning App Builder","select":1,"question":"Students can enroll in many Courses, and each Course can have many Students. How should this many-to-many relationship be modeled?","options":["Two unrelated custom objects","A junction object with two master-detail relationships","A hierarchy custom setting","A single formula field"],"answers":[1],"explanation":"A junction object represents the association between two objects and normally uses two master-detail relationships. Each junction record connects one Student to one Course, allowing many records on both sides.","tip":"Many-to-many in Salesforce usually means a junction object between the two primary objects."},{"id":11,"category":"Object Manager and Lightning App Builder","select":2,"question":"Two opportunity teams use different stage values and need different page layouts. Which two configurations work together to provide this experience?","options":["Sales processes","Record types","Public groups","Sharing rules"],"answers":[0,1],"explanation":"A sales process controls the Opportunity Stage values available to a business process. Record types connect users to the appropriate business process, picklist values, and page layout assignment.","tip":"Business processes control selected standard picklists. Record types package the process, picklist choices, and page layout experience."},{"id":12,"category":"Object Manager and Lightning App Builder","select":1,"question":"A field should appear on a Lightning record page only when the High Priority checkbox is selected. What should the administrator use?","options":["A role hierarchy","A lead assignment rule","A report filter","Dynamic Forms field visibility"],"answers":[3],"explanation":"Dynamic Forms lets administrators place fields and field sections as components and apply visibility rules based on record data, user attributes, or device form factor.","tip":"Conditional field visibility on a Lightning page points to Dynamic Forms, not a traditional page layout alone."},{"id":13,"category":"Object Manager and Lightning App Builder","select":2,"question":"Which two statements correctly distinguish page layouts from Lightning record pages?","options":["Page layouts control fields, related lists, and many actions available for a record","Page layouts determine organization-wide defaults","Lightning App Builder controls page regions and component placement","Lightning pages replace field-level security"],"answers":[0,2],"explanation":"Page layouts control much of the record detail configuration, including fields, buttons, actions, and related lists. Lightning App Builder controls the composition of the Lightning page, such as tabs, regions, components, and conditional visibility. Neither overrides security.","tip":"Page layout answers 'what record elements are available?' Lightning App Builder answers 'how are components arranged and shown?'"},{"id":14,"category":"Object Manager and Lightning App Builder","select":1,"question":"A formula on Opportunity must display the parent Account's Industry value. Which formula capability should be used?","options":["A cross-object formula referencing the parent Account","A summary formula in a report only","A roll-up summary on Opportunity","A workflow outbound message"],"answers":[0],"explanation":"A cross-object formula on a child record can reference fields from a related parent record. A roll-up summary works in the opposite direction by aggregating detail records onto a master.","tip":"Cross-object formula pulls a parent value down. Roll-up summary aggregates child values up."},{"id":15,"category":"Object Manager and Lightning App Builder","select":1,"question":"A child record must be allowed to exist without a parent and must retain its own owner and sharing behavior. Which relationship is most appropriate?","options":["Master-detail relationship","Self relationship is required","Lookup relationship","Many-to-many relationship only"],"answers":[2],"explanation":"A lookup relationship is loosely coupled: the child can generally exist independently and retains its own ownership and sharing. In master-detail, the detail record depends on the master and inherits key behavior.","tip":"Independent lifecycle and ownership usually indicate lookup. Tight dependency and inherited behavior indicate master-detail."},{"id":16,"category":"Object Manager and Lightning App Builder","select":1,"question":"An administrator removes a custom field and later learns that users still need its historical data. What should the administrator check first?","options":["The campaign influence settings","The role hierarchy","The AppExchange listing","The Deleted Fields area in Object Manager"],"answers":[3],"explanation":"Deleted custom fields are placed in the object's Deleted Fields area for a limited recovery period. Restoring the field can also restore its stored data, although dependencies and formulas should be reviewed.","tip":"Deleting a custom field is not always immediately permanent, but recovery is time-limited and dependencies matter."},{"id":17,"category":"Sales and Marketing Applications","select":1,"question":"What records can Salesforce create during a standard lead conversion?","options":["A quote and an order only","Only a campaign and a case","An account, a contact, and optionally an opportunity","A user and a public group"],"answers":[2],"explanation":"Lead conversion creates or associates an Account and Contact and can optionally create an Opportunity. The original lead becomes converted and is no longer worked as an open lead.","tip":"Lead conversion transforms a prospect into core sales records: Account, Contact, and optionally Opportunity."},{"id":18,"category":"Sales and Marketing Applications","select":1,"question":"Marketing wants to distinguish campaign members who were Sent, Responded, Attended, or No Show for each campaign. What should be configured?","options":["Account teams","Campaign member statuses","Case statuses","Opportunity forecast categories"],"answers":[1],"explanation":"Campaign member statuses track how leads and contacts progress within a specific campaign. Administrators can define the relevant status values and indicate which statuses count as responses.","tip":"Campaign member status describes a person's participation in one campaign, not their general lead or contact status."},{"id":19,"category":"Sales and Marketing Applications","select":1,"question":"A company sells products at different prices to retail and wholesale customers. Which Salesforce features should support this requirement?","options":["Multiple price books with products and price book entries","Case escalation rules","Two recycle bins","Multiple role hierarchies"],"answers":[0],"explanation":"Products define what is sold, while price books and price book entries define the available prices. Opportunities can use the appropriate price book and include products as opportunity line items.","tip":"Product is the item. Price book entry connects a product to a price in a specific price book."},{"id":20,"category":"Sales and Marketing Applications","select":1,"question":"Different business units need different Opportunity Stage values and sales paths. Which configuration should the administrator use?","options":["Sales processes assigned through opportunity record types","Account sharing rules only","Case queues","Dashboard filters"],"answers":[0],"explanation":"Sales processes define which Opportunity Stage values are available. Opportunity record types connect the appropriate sales process and page layout to each business unit or user group.","tip":"For standard sales stages, remember the pair: sales process plus record type."},{"id":21,"category":"Sales and Marketing Applications","select":3,"question":"A public website must capture leads, route them by country, and immediately send an appropriate confirmation email. Which three features should be used?","options":["An active lead assignment rule","A case escalation rule","Web-to-Lead","A lead auto-response rule"],"answers":[0,2,3],"explanation":"Web-to-Lead captures submitted form data as leads. Lead assignment rules route the records, and auto-response rules send an immediate email based on record criteria. Case escalation rules apply to cases, not leads.","tip":"Separate the flow into capture, routing, and response. Salesforce often provides a dedicated feature for each step."},{"id":22,"category":"Service and Support Applications","select":1,"question":"Customers should submit support requests through a form on the company's website. Which standard capability should the administrator use?","options":["Web-to-Lead","Opportunity teams","Web-to-Case","Email-to-Case"],"answers":[2],"explanation":"Web-to-Case generates HTML that captures website submissions as Case records. It is designed for support requests rather than sales prospects.","tip":"Website support request equals Web-to-Case. Website prospect capture equals Web-to-Lead."},{"id":23,"category":"Service and Support Applications","select":1,"question":"Support emails sent to help@company.com must automatically create cases in Salesforce. Which feature is designed for this?","options":["Chatter email notifications","Campaign email","Mass Email","Email-to-Case"],"answers":[3],"explanation":"Email-to-Case converts inbound support emails into Case records and preserves the conversation information needed by service agents.","tip":"Inbound support mailbox to Case is Email-to-Case."},{"id":24,"category":"Service and Support Applications","select":1,"question":"New cases should be routed to different queues according to product family and customer tier. What should the administrator configure?","options":["A dashboard subscription","A case assignment rule","A compact layout","A validation rule"],"answers":[1],"explanation":"Case assignment rules evaluate criteria and assign new or edited cases to users or queues. Queues help groups of agents own and claim work.","tip":"Assignment rules answer 'who should own this new record?'"},{"id":25,"category":"Service and Support Applications","select":1,"question":"A high-priority case must be reassigned and the support manager notified if it remains open for four hours. Which feature should be used?","options":["A duplicate rule","A case escalation rule","A lead assignment rule","A campaign hierarchy"],"answers":[1],"explanation":"Case escalation rules monitor case age against defined criteria and can reassign cases and send notifications when escalation times are reached.","tip":"Escalation is time-based service management. Assignment is initial routing."},{"id":26,"category":"Service and Support Applications","select":2,"question":"A company wants one approved knowledge base for internal agents and selected articles for customers in an Experience Cloud site. Which two capabilities are central to the solution?","options":["Opportunity splits","Lead queues","Salesforce Knowledge","Appropriate audience and visibility configuration for articles"],"answers":[2,3],"explanation":"Salesforce Knowledge manages reusable support content. Article visibility, publication status, channels, and site access determine which audiences can find each article.","tip":"Knowledge is the content system; visibility and publication settings determine who can consume the content."},{"id":27,"category":"Productivity and Collaboration","select":1,"question":"A salesperson must remember to call a customer next Tuesday, but no meeting time has been agreed. Which activity should be created?","options":["An event","A case","A campaign","A task"],"answers":[3],"explanation":"A task represents work to complete and can have a due date without reserving a specific time. An event represents a scheduled calendar occurrence with a start and end time.","tip":"Task means to-do. Event means scheduled time on a calendar."},{"id":28,"category":"Productivity and Collaboration","select":1,"question":"A confidential project team needs a Chatter group that nonmembers cannot find in list views or search results. Which group type is appropriate?","options":["Unlisted group","Case queue","Private group","Public group"],"answers":[0],"explanation":"An unlisted Chatter group provides greater privacy than a private group because nonmembers cannot find it in list views, feeds, or search results. Private groups protect posts and files but can still expose limited group details to nonmembers.","tip":"Private protects the content; unlisted also hides the group from discovery by nonmembers."},{"id":29,"category":"Productivity and Collaboration","select":1,"question":"Which layout determines the key fields shown in the highlights area of a record in the Salesforce mobile app?","options":["Search layout only","Report layout","Compact layout","Home page layout"],"answers":[2],"explanation":"Compact layouts identify the most important fields for a record and influence the highlights panel in Lightning Experience and mobile record headers.","tip":"Compact layout means concise, high-priority record information—especially important on mobile."},{"id":30,"category":"Productivity and Collaboration","select":2,"question":"Which two items are normally represented in Salesforce activity management?","options":["Tasks","Events","Profiles","Permission set groups"],"answers":[0,1],"explanation":"Tasks and events are the core activity records used to track work and scheduled interactions. Profiles and permission set groups are security configuration records.","tip":"Activity management centers on work performed and interactions scheduled."},{"id":31,"category":"Productivity and Collaboration","select":1,"question":"An administrator wants to extend Salesforce with a prebuilt agent, app, or service offered by a partner. Where should the administrator look first?","options":["Schema Builder","Role hierarchy","AgentExchange","Recycle Bin"],"answers":[2],"explanation":"AgentExchange is Salesforce's marketplace for discovering partner-built agents, actions, apps, and related services. Administrators should still evaluate security, permissions, licensing, and fit before installation.","tip":"Marketplace questions now distinguish AgentExchange for agentic solutions from traditional configuration tools."},{"id":32,"category":"Data and Analytics Management","select":1,"question":"A business user must import 20,000 new Contacts from a CSV file through a guided interface and does not need an automated process. Which tool is the best fit?","options":["Data Loader command line","Data Import Wizard","Mass Transfer Records","A dashboard"],"answers":[1],"explanation":"Data Import Wizard provides a browser-based guided process for supported standard and custom objects and is well suited to smaller, one-time imports. Data Loader is better for larger volumes, broader object support, or repeatable operations.","tip":"Wizard means guided and smaller-scale. Data Loader means larger, more flexible, and better for repeatable operations."},{"id":33,"category":"Data and Analytics Management","select":1,"question":"An integration must update 1.5 million records every night. Which data tool is most appropriate?","options":["Data Loader or an API-based integration","A list view inline edit","Data Import Wizard","A manual merge"],"answers":[0],"explanation":"High-volume, repeatable data operations should use Data Loader or an API-based integration. The Data Import Wizard is intended for smaller, guided imports and is not an enterprise-scale scheduled integration tool.","tip":"Volume plus repeatability usually moves the answer away from the browser wizard and toward Data Loader or APIs."},{"id":34,"category":"Data and Analytics Management","select":2,"question":"An external billing system sends records with its own unique customer identifier. Which two choices best support inserting new records and updating existing ones without using Salesforce record IDs?","options":["Use a compact layout","Use an upsert operation","Create a dashboard filter","Mark a field as an External ID"],"answers":[1,3],"explanation":"An External ID stores the identifier from another system. Upsert uses an ID or external ID to update a matching record or insert a new record when no match exists.","tip":"External ID identifies the record across systems; upsert combines update and insert behavior."},{"id":35,"category":"Data and Analytics Management","select":2,"question":"A company wants Salesforce to identify possible duplicate Contacts and block users from saving exact duplicates. Which two features should be configured?","options":["A matching rule","A duplicate rule","A dashboard running user","A role hierarchy"],"answers":[0,1],"explanation":"A matching rule defines how records are compared. A duplicate rule decides what happens when a potential duplicate is found, such as allowing with an alert or blocking the save.","tip":"Matching rule finds the match. Duplicate rule controls the response."},{"id":36,"category":"Data and Analytics Management","select":1,"question":"Users must not save a Closed Won opportunity when the Amount is blank. What is the most direct declarative solution?","options":["A sharing rule","A compact layout","A report subscription","A validation rule"],"answers":[3],"explanation":"A validation rule evaluates record data during save and prevents the save when the formula returns true. It also displays an error message explaining how the user should correct the record.","tip":"When the requirement is 'do not allow this record to save,' validation rule is usually the first answer to evaluate."},{"id":37,"category":"Data and Analytics Management","select":1,"question":"What does a report type primarily determine?","options":["Which records and object relationships are available to the report","Which currency the organization uses","Which users can log in","Which automation runs first"],"answers":[0],"explanation":"A report type defines the primary object and the related object relationships and fields that a report can use. Record-level visibility still depends on the viewer's access.","tip":"Report type defines the report's data model, not the user's security."},{"id":38,"category":"Data and Analytics Management","select":1,"question":"Regional managers should open the same dashboard but see data according to their own record access. Which dashboard capability should be used?","options":["A compact layout","A public list view","A dashboard with a fixed running user","A dynamic dashboard"],"answers":[3],"explanation":"A dynamic dashboard runs as the logged-in viewer, allowing one dashboard to present data based on each person's access. A dashboard with a fixed running user shows data according to that selected user.","tip":"Dynamic dashboard means 'run as the viewer.'"},{"id":39,"category":"Data and Analytics Management","select":1,"question":"Executives should all see the same company-wide metrics regardless of their individual record access. What is the usual dashboard configuration?","options":["Give every executive Modify All Data","Change all organization-wide defaults to Public Read/Write","Use an appropriate fixed running user","Use a dynamic dashboard"],"answers":[2],"explanation":"A dashboard with a fixed running user displays data according to that user's access. The running user should have the appropriate visibility, without broadly weakening security for everyone else.","tip":"Same data for every viewer points to a fixed running user. Personalized data points to a dynamic dashboard."},{"id":40,"category":"Data and Analytics Management","select":2,"question":"A user can open a report folder but sees fewer records than a colleague in the same report. Which two principles explain this behavior?","options":["Report results respect the viewer's underlying record access","Folder sharing automatically grants access to every record","Folder access controls access to the report definition","Report filters override organization-wide defaults"],"answers":[0,2],"explanation":"Report folder sharing determines who can view or manage the report asset. The records returned by the report still respect object permissions and record-level sharing for the person running it.","tip":"Access to a report is not the same as access to every record the report could query."},{"id":41,"category":"Automation","select":1,"question":"A field on the record being saved must be updated before the record is committed, and no related records need to be created. Which automation is generally most efficient?","options":["An approval process","A before-save record-triggered flow","A dashboard refresh","A scheduled flow"],"answers":[1],"explanation":"Before-save record-triggered flows are optimized for updating fields on the same record before it is saved. They avoid an additional database update and are often called fast field updates.","tip":"Same record, before save, field update only: think before-save flow."},{"id":42,"category":"Automation","select":1,"question":"After an opportunity becomes Closed Won, Salesforce must create a related onboarding task. Which automation is appropriate?","options":["An after-save record-triggered flow","A matching rule","A before-save flow","A validation rule"],"answers":[0],"explanation":"Creating a related record requires an after-save flow because the original record must already exist in the database. Before-save flows are limited to fast updates on the triggering record.","tip":"Create or update related records after the original save: use an after-save path."},{"id":43,"category":"Automation","select":1,"question":"Users need a guided, multi-screen wizard that collects information and then creates several records. Which tool should the administrator use?","options":["A compact layout","A screen flow","A sharing rule","A validation rule"],"answers":[1],"explanation":"A screen flow provides interactive screens, conditional logic, and record operations. It can be launched from Lightning pages, actions, utility bars, Experience sites, and other supported surfaces.","tip":"User interaction plus guided steps almost always points to a screen flow."},{"id":44,"category":"Automation","select":1,"question":"Every night, Salesforce must find open opportunities that have not been updated in 30 days and create follow-up tasks. Which automation fits best?","options":["A login flow","A validation rule","A schedule-triggered flow","A before-save flow"],"answers":[2],"explanation":"A schedule-triggered flow runs at a defined time and can query records that meet criteria, making it appropriate for recurring batch-style business checks.","tip":"No user save event, recurring time-based scan: schedule-triggered flow."},{"id":45,"category":"Automation","select":1,"question":"Discount requests above 25% must be submitted to a manager, lock the record during review, and support approve or reject outcomes. Which feature is designed for this?","options":["A dashboard filter","A sharing rule","A duplicate rule","An approval process"],"answers":[3],"explanation":"Approval processes route records to approvers and support submission actions, record locking, approval actions, rejection actions, and recall behavior.","tip":"Formal human approval, record locking, and approve/reject outcomes point to an approval process."},{"id":46,"category":"Automation","select":1,"question":"A flow calls an external action that can fail. What should the administrator add to handle the error gracefully?","options":["A new role","A campaign member status","A fault path","A report type"],"answers":[2],"explanation":"A fault path captures errors from flow elements so the flow can log the problem, notify an administrator, or present a useful message instead of failing without context.","tip":"Production-ready flows need error handling, especially around record operations, subflows, and external actions."},{"id":47,"category":"Automation","select":2,"question":"A record-triggered flow should run only when Status changes from any other value to Closed. Which two design choices are most important?","options":["Run the flow on every record access","Use entry conditions for Status = Closed","Check that the field changed or run only when the record is updated to meet the condition","Remove all start conditions"],"answers":[1,2],"explanation":"Strong start conditions reduce unnecessary flow interviews. The flow should require the target value and ensure the record has transitioned into that state rather than executing on every unrelated update.","tip":"Use the Start element to prevent work, not merely a Decision element after the flow has already launched."},{"id":48,"category":"Automation","select":1,"question":"Several record-triggered flows run on Opportunity, and their sequence matters. Which capability helps the administrator review and control their order?","options":["Dashboard subscriptions","Schema Builder and field history","Campaign hierarchy","Flow Trigger Explorer and trigger order"],"answers":[3],"explanation":"Flow Trigger Explorer provides a consolidated view of record-triggered flows for an object and lets administrators understand and manage trigger order where supported.","tip":"When multiple flows compete on one object, think orchestration and trigger order rather than relying on creation dates."},{"id":49,"category":"Agentforce","select":3,"question":"Which three elements define the work an Agentforce agent can handle and how it handles it?","options":["Dashboard color palettes","Subagents or topics that group jobs","Actions that perform specific tasks","Instructions that guide behavior"],"answers":[1,2,3],"explanation":"Agentforce organizes work into subagents—called topics in earlier learning materials—with instructions and available actions. Actions can invoke tools such as flows, prompt templates, or Apex depending on the implementation.","tip":"Remember the structure: scope the job, guide the behavior, perform the task. Be familiar with both 'topics' and the newer 'subagents' terminology."},{"id":50,"category":"Agentforce","select":1,"question":"An agent gives generic answers because it is not using the company's approved policy documents. What should the administrator configure to ground responses in trusted content?","options":["A compact layout","An Agentforce Data Library","A campaign hierarchy","A role hierarchy"],"answers":[1],"explanation":"Agentforce Data Library indexes supported knowledge, files, fields, or web sources so generative AI responses can be grounded in approved business information rather than relying only on general model knowledge.","tip":"Grounding improves relevance and trust by giving the agent an approved source of business context."},{"id":51,"category":"Agentforce","select":1,"question":"An agent should access only the records and actions required for its job. Which security approach is best?","options":["Use a dedicated agent user and least-privilege permissions","Set all organization-wide defaults to Public Read/Write","Disable field-level security","Grant Modify All Data to every user"],"answers":[0],"explanation":"Agentforce security should follow least privilege. A dedicated agent user or execution context should receive only the permissions needed for its approved use cases, while sharing and field security remain part of the control model.","tip":"AI does not replace Salesforce security. Design agent access with the same least-privilege discipline used for human users and integrations."},{"id":52,"category":"Agentforce","select":2,"question":"Before activating an agent for employees, which two steps best help an administrator validate and improve its behavior?","options":["Review agent analytics, sessions, or observability data","Give the agent unrestricted access to simplify troubleshooting","Test realistic requests in Preview and inspect the execution details","Skip testing because standard actions are always correct"],"answers":[0,2],"explanation":"Preview testing reveals how the agent interprets requests and which instructions, subagents, and actions it uses. Observability and analytics help administrators identify adoption, quality, and performance issues after controlled rollout.","tip":"Treat an agent as an operational system: test before release, observe after release, and refine continuously."},{"id":53,"category":"Configuration and Setup","select":1,"question":"A Salary field must be hidden from most users but visible to selected HR specialists in the user interface, reports, and API access. What is the best configuration?","options":["Place the field in a collapsed Lightning page section","Remove the field from the standard page layout only","Set field-level security to hidden and grant access through an HR permission set","Create a private sharing rule for Salary records"],"answers":[2],"explanation":"Field-level security controls whether a user can see or edit a field across Salesforce surfaces, including reports and API access. A permission set can grant the selected HR specialists access without changing the baseline profile for everyone else. Page layouts affect presentation but do not securely hide a field everywhere.","tip":"For sensitive fields, start with field-level security. Page layouts improve usability; they are not a security boundary."},{"id":54,"category":"Configuration and Setup","select":1,"question":"A permission set group gives contractors the correct collection of permissions except that they must not delete Opportunities. What should the administrator use?","options":["A new organization-wide default","A muting permission set in the permission set group","A criteria-based sharing rule","A role below the sales team"],"answers":[1],"explanation":"A muting permission set suppresses selected permissions that are otherwise granted by permission sets inside the same permission set group. It lets the administrator reuse the group while removing an unwanted permission for that assignment model.","tip":"Permission set groups bundle access. Muting permission sets subtract selected permissions from that bundle."},{"id":55,"category":"Configuration and Setup","select":1,"question":"A user reports that every login attempt fails, but the administrator does not know whether the cause is an IP restriction, invalid password, or another authentication error. Where should the administrator investigate first?","options":["Login History","The Recycle Bin","The role hierarchy","The Setup Audit Trail"],"answers":[0],"explanation":"Login History records login attempts and status information that can reveal errors related to credentials, restrictions, and authentication. The Setup Audit Trail tracks configuration changes, not individual login outcomes.","tip":"Troubleshoot authentication with Login History; troubleshoot configuration changes with Setup Audit Trail."},{"id":56,"category":"Configuration and Setup","select":1,"question":"Customer service users must be prevented from accessing Salesforce outside their approved weekly work schedule. Which profile setting should the administrator configure?","options":["Password history","Session timeout","Default record type","Login hours"],"answers":[3],"explanation":"Login hours on a profile define the days and times when assigned users can access Salesforce. Session timeout controls inactivity after login and does not define an approved weekly schedule.","tip":"Login hours answer when a user can log in. Login IP ranges answer where the user can log in."},{"id":57,"category":"Configuration and Setup","select":1,"question":"Internal Account access is Public Read Only, but external Experience Cloud users must have more restrictive default access. What should the administrator configure?","options":["A second role hierarchy for external users","A dashboard running user","Default External Access in organization-wide defaults","A compact layout for the site"],"answers":[2],"explanation":"Default External Access lets an organization define more restrictive organization-wide defaults for external users than for internal users. Additional sharing can then open only the external access that the business requires.","tip":"External users often need a lower access floor. Use external organization-wide defaults before adding targeted sharing."},{"id":58,"category":"Configuration and Setup","select":1,"question":"A support manager must read, edit, transfer, and delete every Case regardless of sharing, but should not receive unrestricted access to other objects. Which permission is most appropriate?","options":["View All on Case","Modify All on Case","View Setup and Configuration","Modify All Data"],"answers":[1],"explanation":"Modify All on the Case object grants full access to all Case records regardless of sharing while keeping the permission scoped to that object. View All does not grant edit or delete access, and Modify All Data is much broader than required.","tip":"View All and Modify All bypass record sharing for one object. View All Data and Modify All Data apply across the org."},{"id":59,"category":"Configuration and Setup","select":1,"question":"A team needs a sandbox for user acceptance testing that includes configuration plus a representative subset of production records. Which sandbox type is the best fit?","options":["Partial Copy sandbox","Developer sandbox","Scratch org only","Developer Pro sandbox"],"answers":[0],"explanation":"A Partial Copy sandbox includes metadata and a selected subset of production data based on a sandbox template, which makes it suitable for realistic user acceptance testing without requiring a complete production copy.","tip":"Developer sandboxes are mainly configuration and development environments. Partial Copy adds selected production data; Full copies all supported production data."},{"id":60,"category":"Object Manager and Lightning App Builder","select":1,"question":"A custom Compliance Code must be required whenever a record is created through the UI, API, import tools, or automation. How should the administrator enforce this?","options":["Create a private sharing rule","Mark the field required on one page layout","Add the field to the highlights panel","Mark the field required at the field definition"],"answers":[3],"explanation":"A universally required custom field is enforced at the schema level across supported record creation methods. A page-layout requirement affects users working through that assigned layout but is not a universal data requirement for API or automation operations.","tip":"Use field-definition required for universal enforcement. Use page-layout required when the requirement varies by user experience."},{"id":61,"category":"Object Manager and Lightning App Builder","select":2,"question":"Which two field types can serve as the controlling field for a dependent picklist?","options":["Picklist","Long Text Area","Multi-select picklist","Checkbox"],"answers":[0,3],"explanation":"A checkbox or a standard or custom picklist can control the available values in a dependent picklist. Multi-select picklists can be dependent fields but cannot serve as controlling fields.","tip":"Controlling fields narrow choices. Remember: checkbox or picklist can control; multi-select cannot control."},{"id":62,"category":"Object Manager and Lightning App Builder","select":2,"question":"Which two attributes determine the page layout a user receives for a record?","options":["The user's dashboard folder access","The user's profile","The record owner's role","The record's record type"],"answers":[1,3],"explanation":"Page layout assignments are configured by the combination of profile and record type. Roles and report-folder permissions do not select a record's page layout.","tip":"Record type controls the business variation; profile plus record type determines the assigned page layout."},{"id":63,"category":"Object Manager and Lightning App Builder","select":1,"question":"Users want Account search results to display Industry and Customer Priority as columns. Which configuration should the administrator modify?","options":["The Account support process","The Account organization-wide default","The role hierarchy","Search layouts for Account"],"answers":[3],"explanation":"Search layouts control the fields and actions presented in search results and certain lookup or list experiences for an object. They do not change record access.","tip":"When the requirement concerns columns in search results, think search layouts rather than page layouts."},{"id":64,"category":"Object Manager and Lightning App Builder","select":1,"question":"A Lightning record-page action should appear only when an Opportunity is in the Negotiation stage. What should the administrator use?","options":["Dynamic Actions with a visibility filter","A sharing rule","A validation rule","A report chart"],"answers":[0],"explanation":"Dynamic Actions let administrators control the visibility of actions on Lightning record pages based on record fields and other supported criteria. A validation rule can block a save but does not conditionally display an action.","tip":"Dynamic Forms conditionally show fields and sections. Dynamic Actions conditionally show actions."},{"id":65,"category":"Object Manager and Lightning App Builder","select":1,"question":"What normally happens to detail records when their master record is deleted in a master-detail relationship?","options":["The detail records become independent","The detail records are deleted through cascade delete","The detail records are automatically reassigned","The relationship converts to a lookup"],"answers":[1],"explanation":"Master-detail establishes strong ownership and lifecycle dependency. Deleting the master normally deletes its detail records as part of cascade delete, subject to platform behavior and restore considerations.","tip":"Master-detail means inherited ownership, inherited sharing, and dependent lifecycle."},{"id":66,"category":"Object Manager and Lightning App Builder","select":1,"question":"When users select an Account on a custom Project record, they should see only Accounts whose Status is Active. Which feature should the administrator configure?","options":["A roll-up summary field","A campaign hierarchy","A lookup filter","A compact layout"],"answers":[2],"explanation":"A lookup filter restricts or recommends the records available in a lookup based on defined criteria. It is the native way to limit parent-record choices such as showing only active Accounts.","tip":"Use lookup filters to control which records are valid choices in a relationship field."},{"id":67,"category":"Sales and Marketing Applications","select":1,"question":"New leads must be routed to different queues by country and company size. Which configuration provides ordered routing criteria?","options":["A case escalation rule","An opportunity team","A campaign hierarchy","A lead assignment rule with rule entries"],"answers":[3],"explanation":"Lead assignment rules evaluate ordered rule entries and assign matching leads to users or queues. The rule-entry order matters because Salesforce processes the criteria in sequence.","tip":"Routing new leads by field values points to a lead assignment rule."},{"id":68,"category":"Sales and Marketing Applications","select":1,"question":"Several people at a customer influence one Opportunity, and sales leadership wants to record each person's role in the buying decision. What should be used?","options":["Opportunity contact roles","Campaign member statuses","Case teams","Account teams"],"answers":[0],"explanation":"Opportunity contact roles connect Contacts to an Opportunity and describe how each person influences the deal, such as decision maker, evaluator, or executive sponsor.","tip":"Opportunity ownership tracks the seller. Contact roles track the customer-side people involved in the deal."},{"id":69,"category":"Sales and Marketing Applications","select":1,"question":"Sales leadership wants an Opportunity Stage to carry a specific default probability and forecast category. Where is this association configured?","options":["In the dashboard folder","On the Opportunity Stage picklist value","In the account sharing rule","On the campaign member status"],"answers":[1],"explanation":"Opportunity Stage values are configured with associated probability and forecast category information. Sales processes then determine which stage values are available for particular record types.","tip":"Stage is more than a label: it is tied to probability and forecasting behavior."},{"id":70,"category":"Sales and Marketing Applications","select":1,"question":"An administrator is adding a Product to a custom wholesale price book, but the product has never been priced before. What must normally be created first?","options":["A campaign member record","An opportunity split","A standard price in the Standard Price Book","A lead conversion process"],"answers":[2],"explanation":"A product normally needs an active standard price before it can be added to a custom price book with another price. The Standard Price Book establishes the product's standard price-book entry.","tip":"Products become sellable through price-book entries. Standard price usually comes before custom price-book pricing."},{"id":71,"category":"Sales and Marketing Applications","select":1,"question":"Marketing runs separate email, webinar, and event campaigns for one annual initiative and wants aggregate statistics across them. What should the administrator configure?","options":["An account team","A sales process","A campaign hierarchy","A support process"],"answers":[2],"explanation":"A campaign hierarchy relates campaigns under a parent initiative and provides roll-up statistics that help marketers analyze the combined performance of the related campaigns.","tip":"Use campaign hierarchy for parent initiatives and aggregated campaign performance."},{"id":72,"category":"Service and Support Applications","select":1,"question":"Customers should receive different acknowledgement emails when cases are created, based on the case origin and product. Which feature should the administrator configure?","options":["A matching rule","A case auto-response rule","A role hierarchy","A dashboard subscription"],"answers":[1],"explanation":"Case auto-response rules send email responses to the person who submitted a case and can select different email templates through ordered rule entries.","tip":"Assignment rules route the case internally. Auto-response rules acknowledge the customer externally."},{"id":73,"category":"Service and Support Applications","select":2,"question":"Two support teams need different Case Status values and different page layouts. Which two configurations should work together?","options":["Record types","Public groups","Escalation actions","Support processes"],"answers":[0,3],"explanation":"A support process defines the Case Status values available to a process. Record types connect the appropriate support process, picklist values, and page layout to the relevant users.","tip":"For Cases, the business process that controls Status values is the support process."},{"id":74,"category":"Service and Support Applications","select":1,"question":"A complex Case regularly requires an account manager, technical specialist, and legal reviewer, each with a defined role and record access. What should be configured?","options":["A territory model","A forecast category","A campaign hierarchy","A case team"],"answers":[3],"explanation":"Case teams let multiple users collaborate on a Case with defined team roles and access levels. Predefined case teams can make recurring team compositions easier to add.","tip":"Use teams when several people need explicit collaborative roles on one record."},{"id":75,"category":"Service and Support Applications","select":1,"question":"Unassigned billing Cases should wait in a shared work pool until an available support user accepts ownership. Which Salesforce feature is appropriate?","options":["A queue","A permission set group","A campaign","A compact layout"],"answers":[0],"explanation":"A queue can own supported records such as Cases until a queue member takes ownership. This creates a shared work pool for teams rather than assigning every record immediately to an individual.","tip":"Queues own work waiting for a person. Public groups are primarily collections used for sharing and other access configurations."},{"id":76,"category":"Service and Support Applications","select":1,"question":"Premium customers are promised a first response within two hours and a resolution within eight hours. Which capability is designed to track these service commitments?","options":["Lead assignment rules","Entitlement processes with milestones","Campaign influence","Opportunity splits"],"answers":[1],"explanation":"Entitlement processes and milestones model support terms and time-dependent service targets such as first response and resolution deadlines.","tip":"SLAs and timed support commitments point to entitlements and milestones."},{"id":77,"category":"Productivity and Collaboration","select":1,"question":"A salesperson schedules a customer demonstration for Thursday from 3:00 PM to 4:00 PM. Which activity should be created?","options":["An event","A campaign","A task","A case"],"answers":[0],"explanation":"An event represents a scheduled activity with a start and end time, such as a meeting or demonstration. A task represents work to complete, often without a reserved time block.","tip":"Task means to-do. Event means scheduled time on a calendar."},{"id":78,"category":"Productivity and Collaboration","select":1,"question":"From an Account record, users need an action that creates a new Contact and automatically relates it to that Account. Which action type is the best fit?","options":["A sharing rule","A global action with no context","A dashboard filter","An object-specific quick action"],"answers":[3],"explanation":"An object-specific create-record action launched from an Account can automatically relate the new record to the current Account. Global actions are not inherently tied to the record from which a user is working.","tip":"Object-specific actions carry record context. Global actions are available broadly and do not automatically inherit a parent record."},{"id":79,"category":"Productivity and Collaboration","select":1,"question":"Sales users want to view Opportunities as cards grouped by Stage and drag cards between stages. Which list-view display should they use?","options":["Schema Builder","Joined report","Kanban view","Calendar view"],"answers":[2],"explanation":"Kanban view displays records as cards grouped by a picklist field and supports visual movement between groups where the underlying field can be updated.","tip":"Cards grouped by a picklist value and moved visually point to Kanban."},{"id":80,"category":"Productivity and Collaboration","select":1,"question":"Users want selected field changes on Opportunity to appear automatically in the record's Chatter feed. What must the administrator enable?","options":["A dashboard running user","A sandbox template","Feed tracking for Opportunity and the selected fields","A lead assignment rule"],"answers":[2],"explanation":"Feed tracking publishes changes to selected fields in the record feed, making important updates visible to users who collaborate through Chatter.","tip":"Chatter does not automatically publish every field change. Enable feed tracking and choose the fields that matter."},{"id":81,"category":"Productivity and Collaboration","select":1,"question":"A user repeatedly opens the same dashboard, list view, and Account record and wants quick personal access without changing the app for everyone. Which feature should the user use?","options":["Organization-wide defaults","Campaign influence","Delegated administration","Favorites"],"answers":[3],"explanation":"Favorites provide personal shortcuts to frequently used Salesforce records, lists, dashboards, and other supported items. They do not change navigation or access for other users.","tip":"Favorites are personal navigation shortcuts, not an administrator-controlled security or sharing feature."},{"id":82,"category":"Data and Analytics Management","select":1,"question":"An organization wants a recurring downloadable backup of Salesforce data without building an integration. Which native capability should the administrator schedule?","options":["Data Export service","Schema Builder","Flow Trigger Explorer","Data Import Wizard"],"answers":[0],"explanation":"The Data Export service can create export files for backup on a scheduled or manual basis, subject to edition and frequency availability. Import tools are designed to load data rather than produce a broad backup.","tip":"For native periodic backup files, think Data Export. For large operational imports or updates, think Data Loader."},{"id":83,"category":"Data and Analytics Management","select":1,"question":"A report must show Accounts that do not have any related Opportunities. Which report feature is most appropriate?","options":["A dashboard filter","A cross filter for Accounts without Opportunities","A bucket field","A row-level formula"],"answers":[1],"explanation":"Cross filters include or exclude parent records based on the existence of related child records. An Accounts without Opportunities cross filter directly answers this relationship question.","tip":"Use cross filters for 'with' or 'without' related-record questions."},{"id":84,"category":"Data and Analytics Management","select":1,"question":"A report must summarize Opportunity Amount by both sales region across rows and fiscal quarter across columns. Which report format should be used?","options":["Tabular","Summary","Matrix","Joined only"],"answers":[2],"explanation":"A matrix report groups data by both rows and columns, making it appropriate for comparing aggregates such as region by fiscal quarter. A summary report groups rows but not columns.","tip":"One grouping direction is summary. Two grouping directions—rows and columns—is matrix."},{"id":85,"category":"Data and Analytics Management","select":1,"question":"A business analyst wants to group Opportunity Amount into Small, Medium, and Large ranges in one report without adding a field to the object. What should be used?","options":["A compact layout","A lookup filter","A record type","A bucket field"],"answers":[3],"explanation":"A bucket field categorizes report values into administrator-defined groups without creating a new field on the underlying object. The categorization exists within the report.","tip":"Temporary report-only categories point to bucket fields."},{"id":86,"category":"Data and Analytics Management","select":1,"question":"A report should calculate the number of days each open Case has existed and display the result on every report row. Which feature should be used?","options":["A row-level formula","A custom summary formula","A sharing rule","A dashboard component"],"answers":[0],"explanation":"A row-level formula performs a calculation for each individual record displayed in a report. Summary formulas operate on aggregated values at group or report level.","tip":"Per record equals row-level formula. Aggregate calculation equals summary formula."},{"id":87,"category":"Data and Analytics Management","select":1,"question":"A grouped Opportunity report needs to calculate win rate for each sales region using summarized record counts. Which feature is appropriate?","options":["A lookup relationship","A custom summary formula","A search layout","A validation rule"],"answers":[1],"explanation":"A custom summary formula calculates values from report aggregates and can display results at selected grouping levels, such as a regional win rate.","tip":"When the formula uses summarized totals or counts, use a custom summary formula."},{"id":88,"category":"Data and Analytics Management","select":1,"question":"Executives want one dashboard where they can switch the displayed metrics between North, South, East, and West. What should the administrator add?","options":["A permission set license","A role hierarchy branch","A dashboard filter","A duplicate rule"],"answers":[2],"explanation":"A dashboard filter lets viewers select a value that filters multiple compatible dashboard components, reducing the need to maintain separate dashboards for each region.","tip":"Dashboard filters create reusable views; they do not grant access to records the viewer cannot otherwise see."},{"id":89,"category":"Data and Analytics Management","select":1,"question":"A manager wants an email only when a report meets defined conditions, such as more than 20 overdue Cases. Which capability should be used?","options":["Create a compact layout","Create an account team","Enable field history tracking","Subscribe to the report and set conditions"],"answers":[3],"explanation":"Report subscriptions can deliver report results on a schedule and can use conditions so notifications are sent only when specified thresholds or criteria are met.","tip":"A report subscription is for scheduled or conditional report delivery; a dashboard subscription delivers dashboard snapshots."},{"id":90,"category":"Automation","select":1,"question":"When a Contract is activated, Salesforce must send a reminder 30 days before the Contract End Date. Which Flow capability is designed for this?","options":["A matching rule","A scheduled path in an after-save record-triggered flow","A before-save flow with no scheduled path","A validation rule"],"answers":[1],"explanation":"A scheduled path can run a branch of an after-save record-triggered flow at a time calculated from a date or date-time field on the triggering record.","tip":"Time relative to a record date points to a scheduled path. A recurring scan of many records points to a schedule-triggered flow."},{"id":91,"category":"Automation","select":1,"question":"Several flows need to use the same address-normalization logic. What is the most maintainable declarative design?","options":["Build reusable logic in an autolaunched flow and call it as a subflow","Use a role hierarchy","Copy the elements into every flow","Create a separate dashboard for each flow"],"answers":[0],"explanation":"A reusable autolaunched flow can encapsulate shared logic and be called through a Subflow element. This reduces duplication and makes future updates easier to manage consistently.","tip":"Repeated flow logic is a signal to modularize with subflows."},{"id":92,"category":"Automation","select":1,"question":"A process requires reusable background automation with no user screens and will be called by another flow. Which flow type should be created?","options":["Login flow","Survey flow","Screen flow","Autolaunched flow with no trigger"],"answers":[3],"explanation":"An autolaunched flow with no trigger runs without screens and can expose input and output variables for invocation by another flow or supported automation context.","tip":"No screens plus reusable callable logic points to an autolaunched flow."},{"id":93,"category":"Automation","select":1,"question":"A flow must follow different paths for Gold, Silver, and Bronze customers. Which element should evaluate the conditions and route the flow?","options":["Assignment","Loop","Decision","Pause"],"answers":[2],"explanation":"A Decision element evaluates conditions and directs the flow through different outcomes. Assignment changes variable values, Loop iterates through a collection, and Pause suspends an interview until a later event or time.","tip":"Decision is the flow equivalent of branching logic: if this, follow that outcome."},{"id":94,"category":"Automation","select":1,"question":"After an Opportunity is saved, a flow must perform an external callout without delaying the original record transaction. Which path is most appropriate when supported?","options":["A validation-rule error path","A Run Asynchronously path in an after-save record-triggered flow","A duplicate-rule path","A before-save path"],"answers":[1],"explanation":"A Run Asynchronously path executes after the original transaction is committed and is appropriate for work such as supported external callouts that should not hold up the record save.","tip":"Before-save is for fast same-record updates. Asynchronous after-save work is separated from the original transaction."},{"id":95,"category":"Automation","select":1,"question":"An administrator wants to debug a flow against realistic records but prevent the debug run from permanently changing data. Which option should be enabled?","options":["Rollback mode","Field history tracking","Manual sharing","Campaign influence"],"answers":[0],"explanation":"Rollback mode lets supported flow debug runs execute database operations and then roll them back, helping administrators test behavior without retaining the resulting record changes.","tip":"Debug first, activate later. Use rollback when you need realistic execution without persistent test data changes."},{"id":96,"category":"Automation","select":1,"question":"A manager who normally approves discount requests will be unavailable for two weeks. Which user setting can route approval requests to another person during the absence?","options":["Dashboard Running User","Forecast Manager","Default Opportunity Team","Delegated Approver"],"answers":[3],"explanation":"A delegated approver can act on approval requests for another user when the approval process and user configuration allow delegation. This is different from delegated administration, which grants limited Setup responsibilities.","tip":"Delegated approver handles approvals. Delegated administrator handles selected administrative tasks."},{"id":97,"category":"Agentforce","select":1,"question":"An Agentforce agent must update a Case using deterministic declarative business logic that already exists in Salesforce. Which implementation is appropriate?","options":["Use only a Data Library with no action","Create a campaign hierarchy","Expose an autolaunched flow as a custom agent action","Add the Case fields to a dashboard"],"answers":[2],"explanation":"A custom agent action can reference an autolaunched flow so the agent can execute controlled Salesforce business logic. A Data Library grounds informational responses but does not by itself perform a transactional record update.","tip":"Use grounding for trusted knowledge. Use actions for work the agent must perform."},{"id":98,"category":"Agentforce","select":1,"question":"An agent frequently selects the wrong action when two actions have similar purposes. What should the administrator improve first?","options":["The fiscal year start month","The action names and instructions that explain what each action does and when to use it","The role hierarchy depth","The dashboard color palette"],"answers":[1],"explanation":"The reasoning engine uses action names, descriptions, instructions, and input and output information to decide which action fits a request. Clear, distinct instructions improve predictable action selection.","tip":"For agent behavior, precise instructions are configuration—not decoration. State purpose, conditions, boundaries, and expected inputs clearly."},{"id":99,"category":"Agentforce","select":2,"question":"Which two design choices correctly match an Agentforce requirement to the appropriate capability?","options":["Use a compact layout to train the reasoning engine","Use a custom action to execute a controlled record update","Use a campaign hierarchy to enforce agent permissions","Use a Data Library to ground answers in approved policy content"],"answers":[1,3],"explanation":"Data Libraries provide trusted business context for grounded responses. Agent actions invoke platform functionality such as flows, Apex, external services, or prompt templates to complete tasks. Layouts and campaign structures do not replace these capabilities.","tip":"Ask whether the agent needs to know something or do something. Knowledge suggests grounding; execution suggests an action."},{"id":100,"category":"Agentforce","select":1,"question":"A customer asks an Agentforce service agent to resolve a sensitive issue that falls outside the agent's approved scope. What is the best design?","options":["Define a guardrail and escalation path to a human representative","Hide the conversation from service users","Give the agent unrestricted permissions","Instruct the agent to guess the most likely resolution"],"answers":[0],"explanation":"Clear scope boundaries and human escalation are core guardrails for situations the agent should not handle autonomously. The agent should transfer or route the interaction rather than invent an answer or expand its permissions.","tip":"A trustworthy agent knows when to act, when not to act, and when to escalate."}]};
